import React, { useState, useEffect } from 'react';
import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Tooltip,
  BarChart,
  Bar,
  CartesianGrid,
  XAxis,
  YAxis,
  Legend,
} from 'recharts';

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

const AdminDashboard = ({ token, user, onLogout }) => {
  const [stats, setStats] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deactivateLoading, setDeactivateLoading] = useState({});
  const [reactivateLoading, setReactivateLoading] = useState({});
  const [error, setError] = useState('');

  const getAuthHeaders = () => ({
    Authorization: `Bearer ${token}`,
    'Content-Type': 'application/json',
  });

  useEffect(() => {
    fetchStats();
    fetchUsers();
  }, [token]);

  const fetchStats = async () => {
    try {
      const response = await fetch('/admin/stats', { headers: getAuthHeaders() });
      if (!response.ok) throw new Error('Failed to load stats');
      const data = await response.json();
      setStats(data);
    } catch (err) {
      setError(err.message);
    }
  };

  const fetchUsers = async () => {
    try {
      const response = await fetch('/admin/users?active_only=false', { headers: getAuthHeaders() });
      if (!response.ok) throw new Error('Failed to load users');
      const data = await response.json();
      setUsers(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDeactivate = async (userId) => {
    if (!confirm('Deactivate this user?')) return;
    try {
      setDeactivateLoading(prev => ({...prev, [userId]: true}));
      const response = await fetch(`/admin/users/${userId}/deactivate`, {
        method: 'PATCH',
        headers: getAuthHeaders(),
      });
      if (!response.ok) throw new Error('Failed to deactivate');
      fetchUsers(); // Refresh list
    } catch (err) {
      setError(err.message);
    } finally {
      setDeactivateLoading(prev => ({...prev, [userId]: false}));
    }
  };

  const handleReactivate = async (userId) => {
    if (!confirm('Reactivate this user?')) return;
    try {
      setReactivateLoading(prev => ({...prev, [userId]: true}));
      const response = await fetch(`/admin/users/${userId}/reactivate`, {
        method: 'PATCH',
        headers: getAuthHeaders(),
      });
      if (!response.ok) throw new Error('Failed to reactivate');
      fetchUsers(); // Refresh list
    } catch (err) {
      setError(err.message);
    } finally {
      setReactivateLoading(prev => ({...prev, [userId]: false}));
    }
  };

  if (loading) return <div className="loading">Loading admin dashboard...</div>;

  const loginFrequency = stats?.user_activity?.login_frequency || [];
  const actionsBreakdown = stats?.user_activity?.actions_breakdown || [];
  const topActiveUsers = stats?.user_activity?.top_active_users || [];
  const mlMetrics = stats?.ml_metrics || {};

  return (
    <div className="app-shell admin-shell">
      <div className="bg-orb bg-orb--one" />
      <div className="bg-orb bg-orb--two" />
      <div className="bg-grid bg-grid--dark" />

      <main className="dashboard admin-dashboard">
        <section className="hero-panel glass-panel admin-hero">
          <div className="hero-panel__top">
            <h1>Admin Dashboard</h1>
            <div className="admin-user">
              <span>{user?.name || 'Admin'}</span>
              <button onClick={onLogout} className="btn btn-secondary">Logout</button>
            </div>
          </div>
          {error && <div className="status-banner status-banner--error">{error}</div>}
        </section>

        <section className="dashboard-grid">
          <div className="dashboard-main full-width">
            {/* Stats Cards */}
            <div className="glass-panel stats-grid">
              <div className="stat-card admin-stat">
                <span>Total Users</span>
                <strong>{stats?.total_users || 0}</strong>
              </div>
              <div className="stat-card admin-stat">
                <span>Total Playlists</span>
                <strong>{stats?.total_playlists || 0}</strong>
              </div>
              <div className="stat-card admin-stat">
                <span>Active Last 30d</span>
                <strong>{stats?.recent_active_users || 0}</strong>
              </div>
              <div className="stat-card admin-stat">
                <span>Avg ML Accuracy</span>
                <strong>{mlMetrics?.accuracy ? (mlMetrics.accuracy * 100).toFixed(1) + '%' : 'N/A'}</strong>
              </div>
              <button onClick={fetchStats} className="btn btn-ghost">Refresh</button>
            </div>

            {/* Charts */}
            <div className="glass-panel charts-section">
              <div className="panel-header">
                <h2>Top Moods & Genres</h2>
              </div>
              <div className="charts-row">
                <div className="chart-container">
                  <h3>Top Moods</h3>
                  <ResponsiveContainer width="100%" height={300}>
                    <PieChart>
                      <Pie data={stats?.top_moods || []} cx="50%" cy="50%" outerRadius={80} dataKey="count" nameKey="name">
                        {COLORS.map((entry, index) => (
                          <Cell key={`mood-${index}`} fill={entry} />
                        ))}
                      </Pie>
                      <Tooltip />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
                <div className="chart-container">
                  <h3>Top Genres</h3>
                  <ResponsiveContainer width="100%" height={300}>
                    <PieChart>
                      <Pie data={stats?.top_genres || []} cx="50%" cy="50%" outerRadius={80} dataKey="count" nameKey="name">
                        {COLORS.map((entry, index) => (
                          <Cell key={`genre-${index}`} fill={entry} />
                        ))}
                      </Pie>
                      <Tooltip />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </div>

            <div className="glass-panel charts-section">
              <div className="panel-header">
                <h2>User Activity (30 Days)</h2>
              </div>
              <div className="charts-row">
                <div className="chart-container">
                  <h3>Login Frequency</h3>
                  <ResponsiveContainer width="100%" height={260}>
                    <BarChart data={loginFrequency}>
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis dataKey="date" />
                      <YAxis />
                      <Tooltip />
                      <Legend />
                      <Bar dataKey="count" name="Logins" fill="#0088FE" />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
                <div className="chart-container">
                  <h3>Actions Breakdown</h3>
                  <ResponsiveContainer width="100%" height={260}>
                    <BarChart data={actionsBreakdown}>
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis dataKey="action" />
                      <YAxis />
                      <Tooltip />
                      <Legend />
                      <Bar dataKey="count" name="Actions" fill="#00C49F" />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </div>

            <div className="glass-panel">
              <div className="panel-header">
                <h2>ML Monitoring</h2>
              </div>
              <div className="stats-grid">
                <div className="stat-card admin-stat">
                  <span>Accuracy</span>
                  <strong>{mlMetrics?.accuracy ? (mlMetrics.accuracy * 100).toFixed(1) + '%' : 'N/A'}</strong>
                </div>
                <div className="stat-card admin-stat">
                  <span>Precision</span>
                  <strong>{mlMetrics?.precision == null ? 'N/A' : (mlMetrics.precision * 100).toFixed(1) + '%'}</strong>
                </div>
                <div className="stat-card admin-stat">
                  <span>Recall</span>
                  <strong>{mlMetrics?.recall == null ? 'N/A' : (mlMetrics.recall * 100).toFixed(1) + '%'}</strong>
                </div>
                <div className="stat-card admin-stat">
                  <span>Evaluated Samples</span>
                  <strong>{mlMetrics?.evaluated_samples || 0}</strong>
                </div>
              </div>
              {mlMetrics?.note && <p className="muted-copy">{mlMetrics.note}</p>}
            </div>

            {/* Users Table */}
            <div className="glass-panel users-section">
              <div className="panel-header panel-header--split">
                <h2>Users ({users.length})</h2>
                <button onClick={fetchUsers} className="btn btn-ghost">Refresh</button>
              </div>
              <div className="users-table">
                <table>
                  <thead>
                    <tr>
                      <th>Name</th>
                      <th>Email</th>
                      <th>Playlists</th>
                      <th>Accuracy</th>
                      <th>Last Active</th>
                      <th>Status</th>
                      <th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {users.map((u) => (
                      <tr key={u.id}>
                        <td>{u.name}</td>
                        <td>{u.email}</td>
                        <td>{u.playlists_count}</td>
                        <td>{(u.total_accuracy * 100).toFixed(1)}%</td>
                        <td>{new Date(u.last_activity).toLocaleDateString()}</td>
                        <td>
                          <span className={`status-badge ${u.is_active ? 'active' : 'inactive'}`}>
                            {u.is_active ? 'Active' : 'Inactive'}
                          </span>
                        </td>
                        <td>
                          {u.is_active ? (
                            <button 
                              onClick={() => handleDeactivate(u.id)}
                              disabled={deactivateLoading[u.id]}
                              className="btn btn-danger btn-small"
                            >
                              {deactivateLoading[u.id] ? '...' : 'Deactivate'}
                            </button>
                          ) : (
                            <button 
                              onClick={() => handleReactivate(u.id)}
                              disabled={reactivateLoading[u.id]}
                              className="btn btn-success btn-small"
                            >
                              {reactivateLoading[u.id] ? '...' : 'Reactivate'}
                            </button>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            <div className="glass-panel users-section">
              <div className="panel-header panel-header--split">
                <h2>Most Active Users</h2>
              </div>
              <div className="users-table">
                <table>
                  <thead>
                    <tr>
                      <th>Name</th>
                      <th>Email</th>
                      <th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {topActiveUsers.map((u) => (
                      <tr key={u.user_id}>
                        <td>{u.name}</td>
                        <td>{u.email}</td>
                        <td>{u.actions_count}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </section>
      </main>
    </div>
  );
};

export default AdminDashboard;
